<style>@font-face{font-family:roboto;src:url(assets/fonts/Roboto-Regular.ttf);font-weight:400}@font-face{font-family:roboto;src:url(assets/fonts/Roboto-Bold.ttf);font-weight:700}.cvo-document .cvo-page{padding:0;position:relative}.cvo-document .cvo-subpage{padding:0}#cvo-body{padding:2mm 2mm;font-size:14px;line-height:1.4em;}@media print{#cvo-body{padding:0}}#group-header{padding-bottom:30px}#cvo-profile-wraper{padding:0 10px 10px;width:100%;position:relative}#cvo-profile-wraper:after{display:block;content:" ";clear:both;height:0;width:0}#cvo-profile-avatar-wraper{display:block;height:140px;width:140px;padding:3px;border:3px solid #246b81;border-radius:50%;position:absolute;top:0;left:10px}#cvo-profile-avatar{width:100%;height:100%;border:2px solid #246b81;border-radius:50%}#cvo-profile-info{width:100%;padding-left:140px}#cvo-profile-wraper>div:only-child{width:100%;padding-left:0}#cvo-profile-wraper>div:only-child #cvo-profile-fullname{left:0}#cvo-profile-wraper>div:only-child .contact{padding-left:0}#cvo-profile-info .info{border-bottom:3px solid #246b81;height:71px;color:#246b81;position:relative}#cvo-profile-fullname{font-size:26px;line-height:1em;width:330px;font-weight:500;text-transform:capitalize;position:absolute;bottom:6px;left:10px}#cvo-profile-title{position:absolute;font-size:14px;bottom:10px;right:0;min-width:245px;text-transform:uppercase;text-align:right}#cvo-profile-info .contact{font-size:14px;color:#494949;padding:3px 0 0 10px}#cvo-profile-info .contact .contact-item{margin-top:4px;width:50%;float:left;position:relative;padding-left:17px}#cvo-profile-info .contact .fa{color:#494949;margin-right:8px;width:10px;text-align:center;position:absolute;top:0;left:0}#cvo-profile-phone,#cvo-profile-email,#cvo-profile-address{min-width:130px}#cvo-profile-website{word-break:break-all}#group-main .cvo-block,#group-bottom .cvo-block{padding:5px 10px;padding-bottom:15px}.cvo-block-header{border-bottom:2px solid #ccc;margin-bottom:8px;padding-bottom:8px;text-transform:uppercase;font-size:22px;font-weight:500;color:#246b81}.cvo-block-body{line-height:1.4em;color:#494949;font-size:14px;word-break:break-word}.cvo-education-school,.cvo-experience-company,.cvo-activity-organization{font-weight:600;color:#494949;text-transform:uppercase;font-size:15px}.cvo-education-title,.cvo-experience-position,.cvo-activity-position{color:#246b81;font-weight:500;text-transform:uppercase}.cvo-block-body .row{margin-bottom:15px;position:relative}.cvo-block-body .row:after{content:" ";clear:both;height:0;width:0;display:block}.cvo-block-body .row .row-col-left{width:40%;float:left;padding-right:10px}.cvo-block-body .row .row-col-right{width:60%;float:left}#group-bottom-left{width:50%;float:left;padding-right:2px}#group-bottom-right{width:50%;float:left;padding-left:2px}.cvo-skillrate-bar{background-color:#eee;width:100%;height:8px;border-radius:4px;position:relative;margin-top:4px}.cvo-skillrate-value{width:80%;height:8px;position:absolute;top:0;left:0;background-color:#246b81;border-radius:4px}.cvo-skillrate-bar[bval="1"] .cvo-skillrate-value{width:20%}.cvo-skillrate-bar[bval="2"] .cvo-skillrate-value{width:40%}.cvo-skillrate-bar[bval="3"] .cvo-skillrate-value{width:60%}.cvo-skillrate-bar[bval="4"] .cvo-skillrate-value{width:80%}.cvo-skillrate-bar[bval="5"] .cvo-skillrate-value{width:100%}#interest-table .row{width:50%;float:left}#cv-watermark{position:absolute;right:20px;bottom:10px;font-size:12px;color:#555}@media print{.cvo-document .cvo-page{position:initial}#cv-watermark{right:0;bottom:0}}</style>